118		scope = strings.ToLower(strings.TrimSpace(scope))
119		if name == "" {
120			return nil, fmt.Errorf("plugin name is required")
121		}
122		if scope != "project" {
123			return nil, fmt.Errorf("unsupported plugin scope %q", scope)
124		}
