146	// ComparisonDispatch is the resolver for the comparisonDispatch field.
147	func (r *mutationResolver) ComparisonDispatch(ctx context.Context, arms []*ComparisonArmInput) (*ComparisonDispatchResult, error) {
148		if len(arms) == 0 {
149			return nil, fmt.Errorf("comparison requires at least one arm")
150		}
151		for i, arm := range arms {
152			if arm == nil {
153				return nil, fmt.Errorf("comparison arm %d is required", i)
154			}
155			arm.Model = strings.TrimSpace(arm.Model)
156			arm.Prompt = strings.TrimSpace(arm.Prompt)
157			if arm.Model == "" {
158				return nil, fmt.Errorf("comparison arm %d model is required", i)
159			}
160			if arm.Prompt == "" {
161				return nil, fmt.Errorf("comparison arm %d prompt is required", i)
162			}
163			if arm.Harness != nil {
164				trimmed := strings.TrimSpace(*arm.Harness)
165				arm.Harness = &trimmed
166			}
167			if arm.Provider != nil {
168				trimmed := strings.TrimSpace(*arm.Provider)
169				arm.Provider = &trimmed
170			}
171		}
172	
173		id := newDispatchID("comparison")
174		record := comparisonDispatchRecord{
175			ID:        id,
176			State:     queuedPlaceholderState,
177			ArmCount:  len(arms),
178			Arms:      arms,
179			CreatedAt: time.Now().UTC(),
180		}
181		if err := writeJSONRecord(r.WorkingDir, "comparisons", id, record); err != nil {
182			return nil, err
183		}
184		return &ComparisonDispatchResult{
185			ID:       id,
186			State:    queuedPlaceholderState,
187			ArmCount: len(arms),
188		}, nil
189	}
