262	// QueueSummary is the resolver for the queueSummary field.
263	func (r *queryResolver) QueueSummary(ctx context.Context, projectID string) (*QueueSummary, error) {
264		store := bead.NewStore(filepath.Join(r.projectRoot(projectID), ".ddx"))
265		ready, err := store.Ready()
266		if err != nil {
267			return nil, err
268		}
269		blocked, err := store.BlockedAll()
270		if err != nil {
271			return nil, err
272		}
273		all, err := store.ReadAll()
274		if err != nil {
275			return nil, err
276		}
277		var inProgress int
278		for _, b := range all {
279			if b.Status == bead.StatusInProgress || b.Status == "in-progress" {
280				inProgress++
281			}
282		}
283		return &QueueSummary{
284			Ready:      len(ready),
285			Blocked:    len(blocked),
286			InProgress: inProgress,
287		}, nil
288	}
