290	// QueueAndWorkersSummary backs the global drain indicator (ddx-b6cf025c).
291	// Returns zeros — not an error — for unknown or empty projects so the nav
292	// component can render without special-casing failures.
293	func (r *queryResolver) QueueAndWorkersSummary(ctx context.Context, projectID string) (*QueueAndWorkersSummary, error) {
294		out := &QueueAndWorkersSummary{}
295		// Only resolve ready beads when the projectID maps to a real project.
296		// Unknown IDs return zeros rather than falling back to WorkingDir so the
297		// indicator does not surface an unrelated project's queue depth.
298		if r.State != nil {
299			if proj, ok := r.State.GetProjectSnapshotByID(projectID); ok && proj.Path != "" {
300				store := bead.NewStore(filepath.Join(proj.Path, ".ddx"))
301				if ready, err := store.Ready(); err == nil {
302					out.ReadyBeads = len(ready)
303				}
304			}
305			workers := r.State.GetWorkersGraphQL(projectID)
306			out.TotalWorkers = len(workers)
307			for _, w := range workers {
308				if w != nil && w.State == "running" {
309					out.RunningWorkers++
310				}
311			}
312		}
313		// Surface the optional workers.max_count cap so the UI can pre-emptively
314		// disable the `+ Add worker` affordance rather than relying on a server
315		// error from workerDispatch (ddx-b6cf025c review finding).
316		if cfg, err := config.LoadWithWorkingDir(r.projectRoot(projectID)); err == nil && cfg != nil && cfg.Workers != nil && cfg.Workers.MaxCount != nil {
317			v := *cfg.Workers.MaxCount
318			out.MaxCount = &v
319		}
320		return out, nil
321	}
