391	// PaletteSearch is the resolver for the paletteSearch field.
392	func (r *queryResolver) PaletteSearch(ctx context.Context, query string) (*PaletteSearchResults, error) {
393		q := strings.TrimSpace(query)
394		out := &PaletteSearchResults{
395			Documents:  []*PaletteDocumentResult{},
396			Beads:      []*PaletteBeadResult{},
397			Actions:    []*PaletteActionResult{},
398			Navigation: []*PaletteNavigationResult{},
399		}
400		if q == "" {
401			return out, nil
402		}
403	
404		matches := collectPaletteMatches(q, r.WorkingDir)
405		sort.SliceStable(matches, func(i, j int) bool {
406			if matches[i].score != matches[j].score {
407				return matches[i].score < matches[j].score
408			}
409			return matches[i].sortKey < matches[j].sortKey
410		})
411		if len(matches) > paletteResultCap {
412			matches = matches[:paletteResultCap]
413		}
414		for _, match := range matches {
415			switch match.kind {
416			case "document":
417				out.Documents = append(out.Documents, &PaletteDocumentResult{Kind: "document", Path: match.id, Title: match.title})
418			case "bead":
419				out.Beads = append(out.Beads, &PaletteBeadResult{Kind: "bead", ID: match.id, Title: match.title})
420			case "action":
421				out.Actions = append(out.Actions, &PaletteActionResult{Kind: "action", ID: match.id, Label: match.title})
422			case "nav":
423				out.Navigation = append(out.Navigation, &PaletteNavigationResult{Kind: "nav", Route: match.id, Title: match.title})
424			}
425		}
426		return out, nil
427	}
