455	func DispatchPluginAction(workingDir string, name string, action string) (string, error) {
456		pluginActionMu.Lock()
457		defer pluginActionMu.Unlock()
458	
459		state, err := registry.LoadState()
460		if err != nil {
461			return "", fmt.Errorf("loading plugin state: %w", err)
462		}
463	
464		switch action {
465		case "install":
466			if entry := state.FindInstalled(name); entry != nil && entry.VerifyFiles() {
467				return "installed", nil
468			}
469			entry, err := installRegistryPlugin(workingDir, state, name)
470			if err != nil {
471				return "", err
472			}
473			if entry != nil && entry.VerifyFiles() {
474				return "installed", nil
475			}
476			return "", fmt.Errorf("plugin %q install completed but recorded files are not present", name)
477		case "update":
478			installed := state.FindInstalled(name)
479			if installed == nil {
480				return "", fmt.Errorf("plugin %q is not installed", name)
481			}
482			pkg, err := registry.BuiltinRegistry().Find(name)
483			if err != nil {
484				return "", fmt.Errorf("plugin %q is not updateable from the built-in registry", name)
485			}
486			if installed.Version == pkg.Version && installed.VerifyFiles() {
487				return "installed", nil
488			}
489			entry, err := installRegistryPlugin(workingDir, state, name)
490			if err != nil {
491				return "", err
492			}
493			if entry != nil && entry.VerifyFiles() {
494				return "installed", nil
495			}
496			return "", fmt.Errorf("plugin %q update completed but recorded files are not present", name)
497		case "uninstall":
498			entry := state.FindInstalled(name)
499			if entry == nil {
500				return "", fmt.Errorf("plugin %q is not installed", name)
501			}
502			if err := registry.UninstallPackage(entry); err != nil {
503				return "", err
504			}
505			state.Remove(name)
506			if err := registry.SaveState(state); err != nil {
507				return "", fmt.Errorf("saving plugin state: %w", err)
508			}
509			return "uninstalled", nil
510		default:
511			return "", fmt.Errorf("unsupported plugin action %q", action)
512		}
513	}
514	
515	func installRegistryPlugin(workingDir string, state *registry.InstalledState, name string) (*registry.InstalledEntry, error) {
516		pkg, err := registry.BuiltinRegistry().Find(name)
517		if err != nil {
518			return nil, err
519		}
520	
521		origDir, _ := os.Getwd()
522		if workingDir != "" && origDir != workingDir {
523			if err := os.Chdir(workingDir); err != nil {
524				return nil, fmt.Errorf("entering project root: %w", err)
525			}
526			defer func() { _ = os.Chdir(origDir) }()
527		}
528	
529		entry, err := registry.InstallPackage(pkg)
530		if err != nil {
531			return nil, fmt.Errorf("installing plugin %q: %w", name, err)
532		}
533		state.AddOrUpdate(entry)
534		if err := registry.SaveState(state); err != nil {
535			return nil, fmt.Errorf("saving plugin state: %w", err)
536		}
537		return state.FindInstalled(name), nil
538	}
