540	func readComparisonRecords(workingDir string) ([]comparisonDispatchRecord, error) {
541		dir := filepath.Join(workingDir, ".ddx", "comparisons")
542		entries, err := os.ReadDir(dir)
543		if os.IsNotExist(err) {
544			return []comparisonDispatchRecord{}, nil
545		}
546		if err != nil {
547			return nil, err
548		}
549		records := make([]comparisonDispatchRecord, 0, len(entries))
550		for _, entry := range entries {
551			if entry.IsDir() || filepath.Ext(entry.Name()) != ".json" {
552				continue
553			}
554			data, err := os.ReadFile(filepath.Join(dir, entry.Name()))
555			if err != nil {
556				return nil, err
557			}
558			var record comparisonDispatchRecord
559			if err := json.Unmarshal(data, &record); err != nil {
560				return nil, fmt.Errorf("parsing comparison record %s: %w", entry.Name(), err)
561			}
562			if record.ID == "" {
563				continue
564			}
565			records = append(records, record)
566		}
567		sort.Slice(records, func(i, j int) bool {
568			if !records[i].CreatedAt.Equal(records[j].CreatedAt) {
569				return records[i].CreatedAt.After(records[j].CreatedAt)
570			}
571			return records[i].ID < records[j].ID
572		})
573		return records, nil
574	}
