576	func writeJSONRecord(workingDir string, kind string, id string, record any) error {
577		dir := filepath.Join(workingDir, ".ddx", kind)
578		if err := os.MkdirAll(dir, 0o755); err != nil {
579			return err
580		}
581		data, err := json.MarshalIndent(record, "", "  ")
582		if err != nil {
583			return err
584		}
585		data = append(data, '\n')
586		return os.WriteFile(filepath.Join(dir, id+".json"), data, 0o644)
587	}
