589	func newDispatchID(prefix string, parts ...string) string {
590		segments := []string{slug(prefix)}
591		for _, part := range parts {
592			if s := slug(part); s != "" {
593				segments = append(segments, s)
594			}
595		}
596		segments = append(segments, randomHex(4))
597		return strings.Join(segments, "-")
598	}
599	
600	func randomHex(n int) string {
601		b := make([]byte, n)
602		if _, err := rand.Read(b); err != nil {
603			return time.Now().UTC().Format("20060102T150405.000000000")
604		}
605		return hex.EncodeToString(b)
606	}
