608	func pluginCatalog(workingDir string) ([]*PluginInfo, error) {
609		reg := registry.BuiltinRegistry()
610		state, err := registry.LoadState()
611		if err != nil {
612			return nil, err
613		}
614	
615		byName := map[string]*PluginInfo{}
616		installedByName := map[string]registry.InstalledEntry{}
617		for _, entry := range state.Installed {
618			installedByName[entry.Name] = entry
619		}
620	
621		for _, pkg := range reg.Packages {
622			info := pluginInfoFromPackage(pkg, workingDir, installedByName[pkg.Name])
623			byName[info.Name] = info
624		}
625		for _, entry := range state.Installed {
626			if _, ok := byName[entry.Name]; ok {
627				continue
628			}
629			info := pluginInfoFromInstalled(entry, workingDir)
630			byName[info.Name] = info
631		}
632	
633		out := make([]*PluginInfo, 0, len(byName))
634		for _, info := range byName {
635			out = append(out, info)
636		}
637		sort.Slice(out, func(i, j int) bool { return out[i].Name < out[j].Name })
638		return out, nil
639	}
