685	func enrichPluginInfoFromDisk(info *PluginInfo, workingDir string, name string, entry registry.InstalledEntry) {
686		for _, root := range pluginRootCandidates(workingDir, name, entry) {
687			if root == "" {
688				continue
689			}
690			if stat, err := os.Stat(root); err != nil || !stat.IsDir() {
691				continue
692			}
693			if info.DiskBytes == 0 {
694				info.DiskBytes = dirSize(root)
695			}
696			if pkg, _, err := registry.LoadPackageManifest(root); err == nil && pkg != nil {
697				if pkg.Version != "" {
698					info.Version = pkg.Version
699				}
700				if pkg.Description != "" {
701					info.Description = pkg.Description
702				}
703				if pkg.Type != "" {
704					info.Type = string(pkg.Type)
705				}
706				if pkg.Source != "" {
707					info.RegistrySource = pkg.Source
708				}
709				if len(pkg.Keywords) > 0 {
710					info.Keywords = append([]string(nil), pkg.Keywords...)
711				}
712				if manifest, err := json.Marshal(pkg); err == nil {
713					info.Manifest = strPtr(string(manifest))
714				}
715			}
716			info.Skills = uniqueStrings(append(info.Skills, scanNamedChildren(root, []string{"skills", ".agents/skills", ".claude/skills"}, "SKILL.md")...))
717			info.Prompts = uniqueStrings(append(info.Prompts, scanNamedChildren(root, []string{"prompts", "library/prompts"}, "")...))
718			info.Templates = uniqueStrings(append(info.Templates, scanNamedChildren(root, []string{"templates", "library/templates"}, "")...))
719		}
720	}
