722	func pluginRootCandidates(workingDir string, name string, entry registry.InstalledEntry) []string {
723		var roots []string
724		if workingDir != "" {
725			roots = append(roots, filepath.Join(workingDir, ".ddx", "plugins", name))
726		}
727		roots = append(roots, registry.ExpandHome(filepath.Join("~", ".ddx", "plugins", name)))
728		for _, f := range entry.Files {
729			expanded := registry.ExpandHome(f)
730			if expanded == "" {
731				continue
732			}
733			roots = append(roots, pluginRootFromRecordedFile(expanded, name))
734		}
735		return uniqueStrings(roots)
736	}
737	
738	func pluginRootFromRecordedFile(path string, name string) string {
739		cleaned := filepath.Clean(path)
740		if filepath.Base(cleaned) == name {
741			return cleaned
742		}
743		for dir := cleaned; dir != "." && dir != string(filepath.Separator); dir = filepath.Dir(dir) {
744			if filepath.Base(dir) == name && filepath.Base(filepath.Dir(dir)) == "plugins" {
745				return dir
746			}
747			next := filepath.Dir(dir)
748			if next == dir {
749				break
750			}
751		}
752		return cleaned
753	}
754	
755	func dirSize(root string) int {
756		var total int64
757		_ = filepath.WalkDir(root, func(path string, d fs.DirEntry, err error) error {
758			if err != nil || d.IsDir() {
759				return nil
760			}
761			if info, err := d.Info(); err == nil {
762				total += info.Size()
763			}
764			return nil
765		})
766		const maxInt32 = int64(1<<31 - 1)
767		if total > maxInt32 {
768			return int(maxInt32)
769		}
770		return int(total)
771	}
772	
773	func scanNamedChildren(root string, relDirs []string, marker string) []string {
774		var out []string
775		for _, rel := range relDirs {
776			base := filepath.Join(root, filepath.FromSlash(rel))
777			entries, err := os.ReadDir(base)
778			if err != nil {
779				continue
780			}
781			for _, entry := range entries {
782				if strings.HasPrefix(entry.Name(), ".") {
783					continue
784				}
785				if marker != "" {
786					if !entry.IsDir() {
787						continue
788					}
789					if _, err := os.Stat(filepath.Join(base, entry.Name(), marker)); err != nil {
790						continue
791					}
792				}
793				out = append(out, entry.Name())
794			}
795		}
796		return out
797	}
