804	type sessionEfficacyCacheEntry struct {
805		fingerprint string
806		snapshot    efficacySnapshot
807	}
808	
809	var sessionEfficacyCache struct {
810		sync.Mutex
811		byQuery map[string]sessionEfficacyCacheEntry
812	}
813	
814	func (r *queryResolver) efficacySnapshot(since, until, projectID *string) (efficacySnapshot, error) {
815		projectRoot := r.WorkingDir
816		if projectID != nil && strings.TrimSpace(*projectID) != "" {
817			projectRoot = r.projectRoot(strings.TrimSpace(*projectID))
818		}
819		startedAfter, err := parseOptionalEfficacyTime("since", since)
820		if err != nil {
821			return efficacySnapshot{}, err
822		}
823		startedBefore, err := parseOptionalEfficacyTime("until", until)
824		if err != nil {
825			return efficacySnapshot{}, err
826		}
827		logDir := agent.SessionLogDirForWorkDir(projectRoot)
828		query := agent.SessionIndexQuery{
829			StartedAfter:  startedAfter,
830			StartedBefore: startedBefore,
831		}
832		cacheKey := sessionEfficacyCacheKey(logDir, startedAfter, startedBefore)
833		fingerprint, err := sessionEfficacyIndexFingerprint(logDir, query)
834		if err != nil {
835			return efficacySnapshot{}, err
836		}
837		sessionEfficacyCache.Lock()
838		if sessionEfficacyCache.byQuery == nil {
839			sessionEfficacyCache.byQuery = map[string]sessionEfficacyCacheEntry{}
840		}
841		if cached, ok := sessionEfficacyCache.byQuery[cacheKey]; ok && cached.fingerprint == fingerprint {
842			sessionEfficacyCache.Unlock()
843			return cached.snapshot, nil
844		}
845		sessionEfficacyCache.Unlock()
846	
847		entries, err := agent.ReadSessionIndex(logDir, query)
848		if err != nil {
849			return efficacySnapshot{}, err
850		}
851		snap := buildSessionIndexEfficacySnapshot(entries)
852		sessionEfficacyCache.Lock()
853		sessionEfficacyCache.byQuery[cacheKey] = sessionEfficacyCacheEntry{fingerprint: fingerprint, snapshot: snap}
854		sessionEfficacyCache.Unlock()
855		return snap, nil
856	}
857	
858	func sessionEfficacyCacheKey(logDir string, startedAfter, startedBefore *time.Time) string {
859		return strings.Join([]string{logDir, timeKey(startedAfter), timeKey(startedBefore)}, "|")
860	}
861	
862	func timeKey(t *time.Time) string {
863		if t == nil {
864			return ""
865		}
866		return t.UTC().Format(time.RFC3339Nano)
867	}
868	
869	func sessionEfficacyIndexFingerprint(logDir string, query agent.SessionIndexQuery) (string, error) {
870		files, err := agent.SessionIndexShardFiles(logDir, query)
871		if err != nil {
872			return "", err
873		}
874		parts := make([]string, 0, len(files))
875		for _, file := range files {
876			info, err := os.Stat(file)
877			if os.IsNotExist(err) {
878				continue
879			}
880			if err != nil {
881				return "", err
882			}
883			parts = append(parts, fmt.Sprintf("%s:%d:%d", file, info.Size(), info.ModTime().UnixNano()))
884		}
885		return strings.Join(parts, "|"), nil
886	}
887	
888	func parseOptionalEfficacyTime(name string, raw *string) (*time.Time, error) {
889		if raw == nil || strings.TrimSpace(*raw) == "" {
890			return nil, nil
891		}
892		value := strings.TrimSpace(*raw)
893		for _, layout := range []string{time.RFC3339Nano, time.RFC3339, "2006-01-02"} {
894			if parsed, err := time.Parse(layout, value); err == nil {
895				utc := parsed.UTC()
896				return &utc, nil
897			}
898		}
899		return nil, fmt.Errorf("%s must be RFC3339 or YYYY-MM-DD, got %q", name, value)
900	}
