902	type sessionEfficacyAttempt struct {
903		RowKey       string
904		BeadID       string
905		Outcome      string
906		Harness      string
907		Provider     string
908		Model        string
909		InputTokens  int
910		OutputTokens int
911		DurationMs   int
912		CostUsd      *float64
913		EvidencePath string
914		CreatedAt    time.Time
915	}
