917	func buildSessionIndexEfficacySnapshot(entries []agent.SessionIndexEntry) efficacySnapshot {
918		grouped := map[string][]sessionEfficacyAttempt{}
919		for _, entry := range entries {
920			attempt := efficacyAttemptFromSession(entry)
921			if attempt.RowKey == "" {
922				continue
923			}
924			grouped[attempt.RowKey] = append(grouped[attempt.RowKey], attempt)
925		}
926		rows := make([]*EfficacyRow, 0, len(grouped))
927		attemptDetails := map[string][]*EfficacyAttempt{}
928		for rowKey, group := range grouped {
929			sort.Slice(group, func(i, j int) bool { return group[i].CreatedAt.After(group[j].CreatedAt) })
930			attemptDetails[rowKey] = make([]*EfficacyAttempt, 0, len(group))
931			var inputTokens, outputTokens, durations []int
932			var costs []float64
933			var successes int
934			for _, attempt := range group {
935				if attempt.Outcome == "succeeded" {
936					successes++
937				}
938				inputTokens = append(inputTokens, attempt.InputTokens)
939				outputTokens = append(outputTokens, attempt.OutputTokens)
940				durations = append(durations, attempt.DurationMs)
941				if attempt.CostUsd != nil {
942					costs = append(costs, *attempt.CostUsd)
943				}
944				attemptDetails[rowKey] = append(attemptDetails[rowKey], &EfficacyAttempt{
945					BeadID:            attempt.BeadID,
946					Outcome:           attempt.Outcome,
947					DurationMs:        attempt.DurationMs,
948					CostUsd:           attempt.CostUsd,
949					EvidenceBundleURL: attempt.EvidencePath,
950				})
951			}
952			parts := strings.Split(rowKey, "|")
953			row := &EfficacyRow{
954				RowKey:             rowKey,
955				Harness:            parts[0],
956				Provider:           parts[1],
957				Model:              parts[2],
958				Attempts:           len(group),
959				Successes:          successes,
960				SuccessRate:        float64(successes) / float64(len(group)),
961				MedianInputTokens:  medianInt(inputTokens),
962				MedianOutputTokens: medianInt(outputTokens),
963				MedianDurationMs:   medianInt(durations),
964				MedianCostUsd:      medianFloatPtr(costs),
965			}
966			if row.SuccessRate < efficacyWarningFloor {
967				row.Warning = &EfficacyWarning{Kind: "below-adaptive-floor", Threshold: floatPtr(efficacyWarningFloor)}
968			}
969			rows = append(rows, row)
970		}
971		sort.Slice(rows, func(i, j int) bool {
972			if rows[i].SuccessRate != rows[j].SuccessRate {
973				return rows[i].SuccessRate > rows[j].SuccessRate
974			}
975			return rows[i].RowKey < rows[j].RowKey
976		})
977	
978		return efficacySnapshot{rows: rows, attempts: attemptDetails}
979	}
