981	func efficacyAttemptFromSession(entry agent.SessionIndexEntry) sessionEfficacyAttempt {
982		model := firstNonEmpty(entry.Model, "unknown")
983		provider := firstNonEmpty(entry.Provider, providerFromModel(model), entry.Harness, "unknown")
984		harness := firstNonEmpty(entry.Harness, provider, "unknown")
985		cost := efficacyCost(entry)
986		outcome := efficacyOutcome(entry)
987		return sessionEfficacyAttempt{
988			RowKey:       strings.Join([]string{harness, provider, model}, "|"),
989			BeadID:       entry.BeadID,
990			Outcome:      outcome,
991			Harness:      harness,
992			Provider:     provider,
993			Model:        model,
994			InputTokens:  entry.InputTokens,
995			OutputTokens: entry.OutputTokens,
996			DurationMs:   entry.DurationMS,
997			CostUsd:      cost,
998			EvidencePath: efficacyEvidencePath(entry),
999			CreatedAt:    entry.StartedAt,
1000		}
1001	}
