1052	func collectPaletteMatches(query string, workingDir string) []paletteMatch {
1053		var out []paletteMatch
1054		if graph, err := docgraph.BuildGraphWithConfig(workingDir); err == nil {
1055			for _, doc := range graph.AllNodesForOutput() {
1056				if score, ok := paletteScore(query, doc.Path, doc.Title); ok {
1057					out = append(out, paletteMatch{
1058						kind:    "document",
1059						id:      filepath.ToSlash(doc.Path),
1060						title:   doc.Title,
1061						score:   score,
1062						sortKey: "document:" + doc.Path,
1063					})
1064				}
1065			}
1066		}
1067	
1068		store := bead.NewStore(filepath.Join(workingDir, ".ddx"))
1069		if beads, err := store.ReadAll(); err == nil {
1070			for _, b := range beads {
1071				if score, ok := paletteScore(query, b.ID, b.Title); ok {
1072					out = append(out, paletteMatch{kind: "bead", id: b.ID, title: b.Title, score: score, sortKey: "bead:" + b.ID})
1073				}
1074			}
1075		}
1076	
1077		for _, action := range []struct{ id, label string }{
1078			{"drain-queue", "Drain queue"},
1079			{"realign-specs", "Re-align specs"},
1080			{"run-checks", "Run checks"},
1081		} {
1082			if score, ok := paletteScore(query, action.id, action.label); ok {
1083				out = append(out, paletteMatch{kind: "action", id: action.id, title: action.label, score: score, sortKey: "action:" + action.id})
1084			}
1085		}
1086		for _, nav := range []struct{ route, title string }{
1087			{"/beads", "Beads"},
1088			{"/documents", "Documents"},
1089			{"/graph", "Graph"},
1090			{"/workers", "Workers"},
1091			{"/personas", "Personas"},
1092			{"/plugins", "Plugins"},
1093			{"/efficacy", "Efficacy"},
1094		} {
1095			if score, ok := paletteScore(query, nav.route, nav.title); ok {
1096				out = append(out, paletteMatch{kind: "nav", id: nav.route, title: nav.title, score: score, sortKey: "nav:" + nav.route})
1097			}
1098		}
1099		return out
1100	}
