1102	func paletteScore(query string, fields ...string) (int, bool) {
1103		q := strings.ToLower(strings.TrimSpace(query))
1104		if q == "" {
1105			return 0, false
1106		}
1107		terms := strings.Fields(q)
1108		best := 1000
1109		for _, field := range fields {
1110			f := strings.ToLower(field)
1111			if strings.HasPrefix(f, q) {
1112				best = min(best, 0)
1113				continue
1114			}
1115			for _, part := range strings.FieldsFunc(f, func(r rune) bool {
1116				return r == '/' || r == '-' || r == '_' || r == '.' || r == ' ' || r == ':'
1117			}) {
1118				if strings.HasPrefix(part, q) {
1119					best = min(best, 1)
1120				}
1121			}
1122			allTerms := true
1123			for _, term := range terms {
1124				if !strings.Contains(f, term) {
1125					allTerms = false
1126					break
1127				}
1128			}
1129			if allTerms {
1130				best = min(best, 2)
1131			}
1132		}
1133		if best == 1000 {
1134			return 0, false
1135		}
1136		return best, true
1137	}
1138	
1139	func medianInt(values []int) int {
1140		if len(values) == 0 {
1141			return 0
1142		}
1143		sort.Ints(values)
1144		return values[len(values)/2]
1145	}
1146	
1147	func medianFloatPtr(values []float64) *float64 {
1148		if len(values) == 0 {
1149			return nil
1150		}
1151		sort.Float64s(values)
1152		v := values[len(values)/2]
1153		return &v
1154	}
1155	
1156	func firstNonEmpty(values ...string) string {
1157		for _, value := range values {
1158			if strings.TrimSpace(value) != "" {
1159				return strings.TrimSpace(value)
1160			}
1161		}
1162		return ""
1163	}
1164	
1165	func uniqueStrings(values []string) []string {
1166		seen := map[string]bool{}
1167		var out []string
1168		for _, value := range values {
1169			value = strings.TrimSpace(value)
1170			if value == "" || seen[value] {
1171				continue
1172			}
1173			seen[value] = true
1174			out = append(out, value)
1175		}
1176		sort.Strings(out)
1177		return out
1178	}
