57		}
58		if kind != "execute-loop" {
59			return nil, fmt.Errorf("unsupported worker kind %q", kind)
60		}
61	
62		var req struct {
63			Harness       string `json:"harness"`
64			Model         string `json:"model"`
65			Profile       string `json:"profile"`
66			Provider      string `json:"provider"`
67			ModelRef      string `json:"model_ref"`
68			Effort        string `json:"effort"`
69			LabelFilter   string `json:"label_filter"`
70			Once          bool   `json:"once"`
71			PollInterval  string `json:"poll_interval"`
72			NoReview      bool   `json:"no_review"`
73			ReviewHarness string `json:"review_harness"`
74			ReviewModel   string `json:"review_model"`
75			MinTier       string `json:"min_tier"`
76			MaxTier       string `json:"max_tier"`
77		}
78		if rawArgs != nil && *rawArgs != "" {
79			if err := json.Unmarshal([]byte(*rawArgs), &req); err != nil {
80				return nil, fmt.Errorf("invalid worker args JSON: %w", err)
81			}
82		}
83	
84		// Apply .ddx/config.yaml workers.default_spec + enforce workers.max_count
85		// (ddx-b6cf025c). The max_count cap counts currently-running drain workers
86		// for this project so the "+ Add worker" button can refuse cleanly.
87		if wc := loadWorkersConfig(projectRoot); wc != nil {
88			if spec := wc.DefaultSpec; spec != nil {
89				if req.Harness == "" {
90					req.Harness = spec.Harness
91				}
92				if req.Profile == "" {
93					req.Profile = spec.Profile
94				}
95				if req.Effort == "" {
96					req.Effort = spec.Effort
97				}
98				if req.MinTier == "" {
99					req.MinTier = spec.MinTier
100				}
101				if req.MaxTier == "" {
102					req.MaxTier = spec.MaxTier
103				}
104			}
105			if wc.MaxCount != nil && *wc.MaxCount >= 0 {
106				running := a.countRunningDrainWorkers(projectRoot)
107				if running >= *wc.MaxCount {
108					return nil, fmt.Errorf("workers.max_count cap reached: %d running (limit %d)", running, *wc.MaxCount)
109				}
110			}
111		}
112	
113		var pollInterval time.Duration
114		if req.PollInterval != "" {
115			d, err := time.ParseDuration(req.PollInterval)
116			if err != nil {
117				return nil, fmt.Errorf("invalid poll_interval: %w", err)
118			}
119			pollInterval = d
120		}
121	
122		record, err := a.manager.StartExecuteLoop(ExecuteLoopWorkerSpec{
123			ProjectRoot:   projectRoot,
124			Harness:       req.Harness,
125			Model:         req.Model,
126			Profile:       req.Profile,
127			Provider:      req.Provider,
128			ModelRef:      req.ModelRef,
129			Effort:        req.Effort,
130			LabelFilter:   req.LabelFilter,
131			Once:          req.Once,
132			PollInterval:  pollInterval,
133			NoReview:      req.NoReview,
134			ReviewHarness: req.ReviewHarness,
135			ReviewModel:   req.ReviewModel,
136			MinTier:       req.MinTier,
137			MaxTier:       req.MaxTier,
138		})
139		if err != nil {
140			return nil, err
141		}
142		return &ddxgraphql.WorkerDispatchResult{
143			ID:    record.ID,
144			State: record.State,
145			Kind:  record.Kind,
146		}, nil
147	}
