771	// TC-GQL-INT-010: Subscription.beadLifecycle delivers lifecycle events over a real WebSocket.
772	//
773	// Events are pre-loaded into a buffered channel and delivered through the real
774	// subscription resolver (resolver_sub_bead.go). The test verifies all events
775	// arrive in order and that the subscription closes cleanly.
776	func TestIntegration_Subscription_BeadLifecycle(t *testing.T) {
777		workDir, store := setupIntegrationDir(t)
778		state := newTestStateProvider(workDir, store)
779	
780		// Pre-load 2 lifecycle events into a buffered channel.
781		eventCh := make(chan bead.LifecycleEvent, 4)
782		now := time.Now().UTC()
783		events := []bead.LifecycleEvent{
784			{
785				EventID:   "it-aabb-0001",
786				BeadID:    "it-aabb",
787				Kind:      "created",
788				Summary:   "bead it-aabb created: integration test",
789				Timestamp: now,
790			},
791			{
792				EventID:   "it-aabb-0002",
793				BeadID:    "it-aabb",
794				Kind:      "status_changed",
795				Summary:   "status changed from open to closed",
796				Timestamp: now.Add(time.Second),
797			},
798		}
799		for _, e := range events {
800			eventCh <- e
801		}
802		close(eventCh)
803	
804		beadBus := &stubBeadBus{ch: eventCh}
805		h := newGQLHandler(state, workDir, beadBus)
806	
807		ts := httptest.NewServer(h)
808		defer ts.Close()
809	
810		// Establish WebSocket connection using graphql-transport-ws subprotocol.
811		wsURL := "ws" + strings.TrimPrefix(ts.URL, "http") + "/graphql"
812		conn, _, err := websocket.DefaultDialer.Dial(wsURL, map[string][]string{
813			"Sec-WebSocket-Protocol": {"graphql-transport-ws"},
814		})
815		if err != nil {
816			t.Fatalf("WebSocket dial: %v", err)
817		}
818		defer conn.Close()
819	
820		send := func(msg wsMsg) {
821			t.Helper()
822			data, _ := json.Marshal(msg)
823			if err := conn.WriteMessage(websocket.TextMessage, data); err != nil {
824				t.Fatalf("WebSocket write: %v", err)
825			}
826		}
827		recv := func() wsMsg {
828			t.Helper()
829			conn.SetReadDeadline(time.Now().Add(5 * time.Second))
830			_, data, err := conn.ReadMessage()
831			if err != nil {
832				t.Fatalf("WebSocket read: %v", err)
833			}
834			var msg wsMsg
835			if err := json.Unmarshal(data, &msg); err != nil {
836				t.Fatalf("unmarshal: %v", err)
837			}
838			return msg
839		}
840	
841		// graphql-transport-ws handshake.
842		send(wsMsg{Type: "connection_init"})
843		ack := recv()
844		if ack.Type != "connection_ack" {
845			t.Fatalf("expected connection_ack, got %q", ack.Type)
846		}
847	
848		// Send subscription.
849		queryPayload, _ := json.Marshal(map[string]string{
850			"query": `subscription { beadLifecycle(projectID: "/integration/test") { eventID beadID kind summary } }`,
851		})
852		send(wsMsg{ID: "sub-1", Type: "subscribe", Payload: queryPayload})
853	
854		// Collect events until the subscription is complete.
855		type eventItem struct {
856			EventID string  `json:"eventID"`
857			BeadID  string  `json:"beadID"`
858			Kind    string  `json:"kind"`
859			Summary *string `json:"summary"`
860		}
861	
862		var received []eventItem
863		ctx, cancel := context.WithTimeout(context.Background(), 10*time.Second)
864		defer cancel()
865	loop:
866		for {
867			select {
868			case <-ctx.Done():
869				t.Fatalf("timed out waiting for subscription events; got %d so far", len(received))
870			default:
871			}
872			msg := recv()
873			switch msg.Type {
874			case "next":
875				var payload struct {
876					Data struct {
877						BL eventItem `json:"beadLifecycle"`
878					} `json:"data"`
879				}
880				if err := json.Unmarshal(msg.Payload, &payload); err != nil {
881					t.Fatalf("unmarshal next payload: %v", err)
882				}
883				received = append(received, payload.Data.BL)
884			case "complete":
885				break loop
886			case "ping":
887				send(wsMsg{Type: "pong"})
888			default:
889				t.Logf("unexpected message type: %q", msg.Type)
890			}
891		}
892	
893		if len(received) != 2 {
894			t.Fatalf("expected 2 events, got %d", len(received))
895		}
896	
897		checks := []struct {
898			eventID string
899			beadID  string
900			kind    string
901			summary string
902		}{
903			{"it-aabb-0001", "it-aabb", "created", "bead it-aabb created: integration test"},
904			{"it-aabb-0002", "it-aabb", "status_changed", "status changed from open to closed"},
905		}
906		for i, chk := range checks {
907			got := received[i]
908			if got.EventID != chk.eventID {
909				t.Errorf("event[%d] eventID: want %q, got %q", i, chk.eventID, got.EventID)
910			}
911			if got.BeadID != chk.beadID {
912				t.Errorf("event[%d] beadID: want %q, got %q", i, chk.beadID, got.BeadID)
913			}
914			if got.Kind != chk.kind {
915				t.Errorf("event[%d] kind: want %q, got %q", i, chk.kind, got.Kind)
916			}
917			if got.Summary == nil || *got.Summary != chk.summary {
918				t.Errorf("event[%d] summary: want %q, got %v", i, chk.summary, got.Summary)
919			}
920		}
921	}
